const items = $input.all();
return items.map(item => {
  const outputText = item.json.output || '{}';
  try {
    const cleanText = outputText.replace(/\\n/g, '').replace(/\\/g, '');
    const data = JSON.parse(cleanText);
    return { json: { propertyValue: data.propertyValue || null, propertyAppreciation: data.propertyAppreciation || null } };
  } catch (e) {
    return { json: { propertyValue: null, propertyAppreciation: null } };
  }
});

const items = $input.all();
function toNum(v){ if(v==null) return v; if(typeof v==='string'){ const n=Number(v); if(!isNaN(n)&&v.trim()!=='') return n; } return v; }
const out = [];
items.forEach(item => {
  const d = item.json;
  const c = {
    praca: d.praca,
    total_propriedades_ano: toNum(d.total_propriedades_ano),
    total_reservas_ano: toNum(d.total_reservas_ano),
    faturamento_total_ano: toNum(d.faturamento_total_ano),
    total_noites_ano: toNum(d.total_noites_ano),
    detalhamento_mensal: (d.detalhamento_mensal || []).map(m => ({
      mes: m.mes,
      total_propriedades: toNum(m.total_propriedades),
      total_reservas: toNum(m.total_reservas),
      faturamento_total: toNum(m.faturamento_total),
      total_noites: toNum(m.total_noites),
      perc_faturamento_ano: toNum(m.perc_faturamento_ano),
      perc_ocupacao_ano: toNum(m.perc_ocupacao_ano)
    }))
  };
  out.push({ json: c });
  if (d.praca === 'Milagres') {
    const copy = JSON.parse(JSON.stringify(c));
    copy.praca = 'Maceió';
    out.push({ json: copy });
  }
});
return out;

const inputData = items[0].json;
const valorImovel = inputData['valor do imóvel'] || 0;
const metaAnual = valorImovel * 0.14;
return [{
  json: {
    cidade: inputData.praca,
    praca: inputData.praca,
    quartos: inputData.quartos,
    detalhamento_mensal: inputData.detalhamento_mensal,
    nome: inputData.nome,
    'valor do imóvel': valorImovel,
    'Valorização anual': inputData['Valorização anual'],
    proprietario: inputData.proprietario,
    'meta anual': Number(metaAnual.toFixed(2))
  }
}];

const input = items[0].json;
const metaAnual = input['meta anual'];

let carnaval2025FoiMarço = true;
const mesFev = input.detalhamento_mensal.find(m => m.mes === 'Fevereiro');
const mesMar = input.detalhamento_mensal.find(m => m.mes === 'Março');
if (mesMar && mesFev && mesMar.faturamento_total > mesFev.faturamento_total * 1.3) {
  carnaval2025FoiMarço = true;
  mesFev.faturamento_total_corrigido = mesMar.faturamento_total;
  mesFev.total_noites_corrigido = mesMar.total_noites;
  mesMar.faturamento_total_corrigido = mesFev.faturamento_total;
  mesMar.total_noites_corrigido = mesFev.total_noites;
}

let totalFaturamento = 0;
input.detalhamento_mensal.forEach(m => {
  if (carnaval2025FoiMarço && (m.mes === 'Fevereiro' || m.mes === 'Março')) {
    totalFaturamento += m.faturamento_total_corrigido || m.faturamento_total || 0;
  } else {
    totalFaturamento += m.faturamento_total || 0;
  }
});

const mensal = {};
input.detalhamento_mensal.forEach(m => {
  const noites = m.total_noites || 0;
  const faturamento = m.faturamento_total || 0;
  const diariaMedia = noites > 0 ? faturamento / noites : 0;
  const fc = carnaval2025FoiMarço && (m.mes === 'Fevereiro' || m.mes === 'Março') ? (m.faturamento_total_corrigido || m.faturamento_total) : (m.faturamento_total || 0);
  const nc = carnaval2025FoiMarço && (m.mes === 'Fevereiro' || m.mes === 'Março') ? (m.total_noites_corrigido || m.total_noites) : (m.total_noites || 0);
  mensal[m.mes] = { faturamento_original: faturamento, faturamento_corrigido: fc, noites_original: noites, noites_corrigidas: nc, diaria_media: diariaMedia, perc_ocupacao_ano: m.perc_ocupacao_ano || 0 };
});

const PERCENTUAL_MINIMO = 0.05;
const metaMinimaBase = metaAnual * PERCENTUAL_MINIMO;
const distInicial = input.detalhamento_mensal.map(item => {
  const d = mensal[item.mes];
  const perc = totalFaturamento > 0 ? d.faturamento_corrigido / totalFaturamento : 1/12;
  return { mes: item.mes, metaInicial: metaAnual * perc };
});

let deficit = 0; const abaixo = []; const acima = [];
distInicial.forEach(i => { if (i.metaInicial < metaMinimaBase) { deficit += (metaMinimaBase - i.metaInicial); abaixo.push(i); } else acima.push(i); });
const metasAjustadas = {};
abaixo.forEach(i => metasAjustadas[i.mes] = metaMinimaBase);
if (acima.length > 0) {
  const totalAcima = acima.reduce((s, m) => s + m.metaInicial, 0);
  acima.forEach(i => {
    const prop = i.metaInicial / totalAcima;
    metasAjustadas[i.mes] = Math.max(metaMinimaBase, i.metaInicial - (deficit * prop));
  });
}
if (metasAjustadas['Março'] > metasAjustadas['Fevereiro']) {
  const t = metasAjustadas['Fevereiro']; metasAjustadas['Fevereiro'] = metasAjustadas['Março']; metasAjustadas['Março'] = t;
}

const DIAS_ANO = 216;
const metaNoitesMensal = {};
input.detalhamento_mensal.forEach(item => {
  const p = item.perc_ocupacao_ano || 8.33;
  let n = Math.round((p / 100) * DIAS_ANO);
  metaNoitesMensal[item.mes] = Math.max(12, Math.min(18, n));
});
if (metasAjustadas['Fevereiro'] > metasAjustadas['Março'] && metaNoitesMensal['Março'] > metaNoitesMensal['Fevereiro']) {
  const t = metaNoitesMensal['Fevereiro']; metaNoitesMensal['Fevereiro'] = metaNoitesMensal['Março']; metaNoitesMensal['Março'] = t;
}

const meta_distribuicao_mensal = input.detalhamento_mensal.map(item => {
  const mes = item.mes;
  const d = mensal[mes];
  const meta_faturamento = Number(metasAjustadas[mes].toFixed(2));
  const meta_noites = metaNoitesMensal[mes];
  const meta_diaria_media = Number((meta_faturamento / meta_noites).toFixed(2));
  return {
    mes,
    percentual_anual: (meta_faturamento / metaAnual * 100).toFixed(1) + '%',
    noites_ano_passado: d.noites_original,
    meta_noites_2026: meta_noites,
    meta_faturamento,
    meta_diaria_media
  };
});

return [{ json: { ...input, meta_noites_anual: Object.values(metaNoitesMensal).reduce((a,b)=>a+b,0), meta_distribuicao_mensal } }];

const mesesMap = { 'Janeiro':'01','Fevereiro':'02','Março':'03','Abril':'04','Maio':'05','Junho':'06','Julho':'07','Agosto':'08','Setembro':'09','Outubro':'10','Novembro':'11','Dezembro':'12' };
const mesesReverso = Object.fromEntries(Object.entries(mesesMap).map(([k,v]) => [v,k]));

const allData = $input.all();
const prepared = $('Prepara os dados').all();
const mesesFaltantes = (prepared[0]?.json?.meses_faltantes) || [];
const out = [];
const hoje = new Date();

for (const item of allData) {
  const data = item.json;
  const idPropriedade = prepared[0]?.json?.idpropriedade || data.idpropriedade || 'ID_NAO_ENCONTRADO';
  const valoresEntrada = {};
  (data.meta_distribuicao_mensal || []).forEach(m => { valoresEntrada[m.mes] = m.meta_faturamento; });

  for (let i = 1; i <= 12; i++) {
    const dataAlvo = new Date(hoje.getFullYear(), hoje.getMonth() + i, 1);
    const mesNum = String(dataAlvo.getMonth() + 1).padStart(2, '0');
    const anoAlvo = dataAlvo.getFullYear();
    const mesAno = `${mesNum}/${anoAlvo}`;
    const nomeMesAlvo = mesesReverso[mesNum];
    const faturamento = valoresEntrada[nomeMesAlvo] || 0;
    out.push({ json: { idpropriedade: idPropriedade, mes: mesAno, faturamento_bruto: faturamento, _mes_nome: nomeMesAlvo } });
  }
}

// Filtro anti-duplicação: mantém apenas meses declarados como faltantes
const filtered = mesesFaltantes.length ? out.filter(x => mesesFaltantes.includes(x.json.mes)) : out;
return filtered;
